sparql_query:
PREFIX goo:    <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:   <http://example.org/resource#>
PREFIX xsd:    <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:    <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:   <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?map
WHERE {
  ?ntl a goo:NTLImage ;
       goo:fromSensor gokg:sensor.VIIRS ;
       goo:representsCounty gokg:LakeCountyFL ;
       goo:acquisitionDateTime ?imageDate ;
       goo:hasOutageMap ?map .
  ?map a goo:OutageMap .
  FILTER (?imageDate >= "2024-03-01T00:00:00Z"^^xsd:dateTime && ?imageDate < "2024-04-01T00:00:00Z"^^xsd:dateTime)
}
ORDER BY ?map
LIMIT 10
